import{_ as e,o as a,c as d,a4 as o}from"./chunks/framework.CDpUjPX_.js";const m=JSON.parse('{"title":"Buscas & Takedowns","description":"","frontmatter":{},"headers":[],"relativePath":"admin/search-takedowns.md","filePath":"admin/search-takedowns.md"}'),r={name:"admin/search-takedowns.md"};function c(s,t,i,n,l,h){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="buscas-takedowns" tabindex="-1">Buscas &amp; Takedowns <a class="header-anchor" href="#buscas-takedowns" aria-label="Permalink to &quot;Buscas &amp; Takedowns&quot;">​</a></h1><p>Gerenciamento de jobs de busca, takedowns de conteudo pirata, crawlers automaticos (Crawler) e targets de busca por nome (BrandWatch).</p><hr><h2 id="search-jobs" tabindex="-1">Search Jobs <a class="header-anchor" href="#search-jobs" aria-label="Permalink to &quot;Search Jobs&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/buscas</code><strong>Arquivo:</strong> <code>app/api/v1/admin/search.py</code></p><h3 id="endpoints-6" tabindex="-1">Endpoints (6) <a class="header-anchor" href="#endpoints-6" aria-label="Permalink to &quot;Endpoints (6)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/search/jobs</code></td><td>Lista jobs de busca com filtros (<code>user_id</code>, <code>status</code>, <code>motor_id</code>, <code>date</code>)</td></tr><tr><td><code>GET</code></td><td><code>/admin/search/jobs/{id}</code></td><td>Detalhe do job</td></tr><tr><td><code>GET</code></td><td><code>/admin/search/jobs/{id}/results</code></td><td>Resultados do job (paginado)</td></tr><tr><td><code>POST</code></td><td><code>/admin/search/jobs/{id}/reprocess</code></td><td>Reprocessar job</td></tr><tr><td><code>GET</code></td><td><code>/admin/search/stats</code></td><td>Estatisticas: total de jobs, por motor, por status</td></tr><tr><td><code>GET</code></td><td><code>/admin/search/users/{user_id}/history</code></td><td>Historico de buscas de um usuario</td></tr></tbody></table><hr><h2 id="takedowns" tabindex="-1">Takedowns <a class="header-anchor" href="#takedowns" aria-label="Permalink to &quot;Takedowns&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/takedowns</code><strong>Arquivo:</strong> <code>app/api/v1/admin/takedowns.py</code></p><h3 id="endpoints-4" tabindex="-1">Endpoints (4) <a class="header-anchor" href="#endpoints-4" aria-label="Permalink to &quot;Endpoints (4)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/takedowns</code></td><td>Lista takedowns com filtros (<code>status</code>, <code>type</code>, <code>user_id</code>, <code>is_auto</code>, <code>date</code>)</td></tr><tr><td><code>GET</code></td><td><code>/admin/takedowns/{id}</code></td><td>Detalhe (inclui evidencia, template usado, verificacoes)</td></tr><tr><td><code>POST</code></td><td><code>/admin/takedowns/{id}/resend</code></td><td>Reenviar notificacao de takedown</td></tr><tr><td><code>POST</code></td><td><code>/admin/takedowns/{id}/verify</code></td><td>Trigger manual de verificacao de remocao</td></tr></tbody></table><h3 id="ciclo-de-vida-do-status" tabindex="-1">Ciclo de vida do status <a class="header-anchor" href="#ciclo-de-vida-do-status" aria-label="Permalink to &quot;Ciclo de vida do status&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pending → sent → acknowledged → removed / failed</span></span></code></pre></div><ul><li><strong>pending</strong> — Takedown criado, aguardando envio</li><li><strong>sent</strong> — Notificacao enviada ao host/plataforma</li><li><strong>acknowledged</strong> — Plataforma confirmou recebimento</li><li><strong>removed</strong> — Conteudo removido com sucesso</li><li><strong>failed</strong> — Falha no envio ou plataforma recusou</li></ul><h3 id="verificacao-de-remocao" tabindex="-1">Verificacao de remocao <a class="header-anchor" href="#verificacao-de-remocao" aria-label="Permalink to &quot;Verificacao de remocao&quot;">​</a></h3><p><strong>Arquivo:</strong> <code>app/services/verification_service.py</code></p><p>O servico executa 3 metodos de verificacao, em ordem:</p><ol><li><strong>HTTP status</strong> — Se o URL retorna 404 ou 410, conteudo considerado removido</li><li><strong>Content check</strong> — Verifica se o conteudo da pagina mudou significativamente (diff)</li><li><strong>pHash compare</strong> — Compara hash perceptual da imagem; se nao encontrada, conteudo removido</li></ol><h3 id="auto-takedown" tabindex="-1">Auto-takedown <a class="header-anchor" href="#auto-takedown" aria-label="Permalink to &quot;Auto-takedown&quot;">​</a></h3><p>Takedowns com <code>is_auto=true</code> sao criados automaticamente quando alertas de alta confianca sao detectados pelos motores. Nao requerem intervencao manual para envio.</p><hr><h2 id="crawlers-crawler" tabindex="-1">Crawlers (Crawler) <a class="header-anchor" href="#crawlers-crawler" aria-label="Permalink to &quot;Crawlers (Crawler)&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/crawlers</code><strong>Arquivo:</strong> <code>app/api/v1/admin/crawlers.py</code></p><p>Gerencia alvos do web crawler automatico (<code>WebCrawlerTarget</code>). O Crawler visita periodicamente os URLs cadastrados em busca de conteudo pirata.</p><h3 id="endpoints-6-1" tabindex="-1">Endpoints (6) <a class="header-anchor" href="#endpoints-6-1" aria-label="Permalink to &quot;Endpoints (6)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/crawlers</code></td><td>Lista alvos do crawler</td></tr><tr><td><code>POST</code></td><td><code>/admin/crawlers</code></td><td>Criar novo alvo</td></tr><tr><td><code>PATCH</code></td><td><code>/admin/crawlers/{id}</code></td><td>Atualizar alvo</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/crawlers/{id}</code></td><td>Remover alvo</td></tr><tr><td><code>GET</code></td><td><code>/admin/crawlers/stats</code></td><td>Estatisticas do crawler</td></tr><tr><td><code>POST</code></td><td><code>/admin/crawlers/{id}/trigger</code></td><td>Trigger manual de crawl</td></tr></tbody></table><h3 id="campos-do-webcrawlertarget" tabindex="-1">Campos do WebCrawlerTarget <a class="header-anchor" href="#campos-do-webcrawlertarget" aria-label="Permalink to &quot;Campos do WebCrawlerTarget&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td><code>url</code></td><td><code>str</code></td><td>URL base do alvo</td></tr><tr><td><code>domain</code></td><td><code>str</code></td><td>Dominio do alvo</td></tr><tr><td><code>crawl_frequency_hours</code></td><td><code>int</code></td><td>Intervalo entre crawls (em horas)</td></tr><tr><td><code>last_crawled_at</code></td><td><code>datetime</code></td><td>Data/hora do ultimo crawl</td></tr><tr><td><code>is_active</code></td><td><code>bool</code></td><td>Se o alvo esta ativo</td></tr></tbody></table><hr><h2 id="targets-brandwatch" tabindex="-1">Targets (BrandWatch) <a class="header-anchor" href="#targets-brandwatch" aria-label="Permalink to &quot;Targets (BrandWatch)&quot;">​</a></h2><p><strong>Admin page:</strong> <code>/targets</code><strong>Arquivo:</strong> <code>app/api/v1/admin/targets.py</code></p><p>Gerencia templates de URL para busca por nome (<code>CrawlTarget</code>). O BrandWatch substitui <code>{name}</code> no template pelas variacoes de nome geradas pelo <code>text_normalizer</code>.</p><h3 id="endpoints-4-1" tabindex="-1">Endpoints (4) <a class="header-anchor" href="#endpoints-4-1" aria-label="Permalink to &quot;Endpoints (4)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/targets</code></td><td>Lista targets</td></tr><tr><td><code>POST</code></td><td><code>/admin/targets</code></td><td>Criar target</td></tr><tr><td><code>PATCH</code></td><td><code>/admin/targets/{id}</code></td><td>Atualizar target</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/targets/{id}</code></td><td>Remover target</td></tr></tbody></table><h3 id="campos-do-crawltarget" tabindex="-1">Campos do CrawlTarget <a class="header-anchor" href="#campos-do-crawltarget" aria-label="Permalink to &quot;Campos do CrawlTarget&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td><code>url_template</code></td><td><code>str</code></td><td>Template com placeholder <code>{name}</code></td></tr><tr><td><code>platform_name</code></td><td><code>str</code></td><td>Nome da plataforma (ex: &quot;Example Site&quot;)</td></tr><tr><td><code>is_active</code></td><td><code>bool</code></td><td>Se o target esta ativo</td></tr></tbody></table><h3 id="exemplo-de-url-template" tabindex="-1">Exemplo de url_template <a class="header-anchor" href="#exemplo-de-url-template" aria-label="Permalink to &quot;Exemplo de url_template&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.com/search?q={name}</span></span></code></pre></div><p>O BrandWatch gera variacoes do nome do conteudo protegido via <code>text_normalizer</code> e substitui <code>{name}</code> em cada template ativo, executando as buscas em paralelo.</p>',40)])])}const u=e(r,[["render",c]]);export{m as __pageData,u as default};
